import{_ as a,o as n,c as l,a2 as o}from"./chunks/framework.B72_uj9U.js";const y=JSON.parse('{"title":"Cross Compilation","description":"Set up cross-compilation toolchains to build your agent for macOS, Linux, and Windows from a single development machine.","frontmatter":{"title":"Cross Compilation","description":"Set up cross-compilation toolchains to build your agent for macOS, Linux, and Windows from a single development machine."},"headers":[],"relativePath":"learn/linear/17-packaging-and-distribution/02-cross-compilation.md","filePath":"learn/linear/17-packaging-and-distribution/02-cross-compilation.md"}'),e={name:"learn/linear/17-packaging-and-distribution/02-cross-compilation.md"};function t(p,s,c,r,i,d){return n(),l("div",null,[...s[0]||(s[0]=[o(`<h1 id="cross-compilation" tabindex="-1">Cross Compilation <a class="header-anchor" href="#cross-compilation" aria-label="Permalink to &quot;Cross Compilation&quot;">​</a></h1><blockquote><p><strong>What you&#39;ll learn:</strong></p><ul><li>How to configure Rust cross-compilation targets for macOS (x86_64 and aarch64), Linux (glibc and musl), and Windows using rustup and cross</li><li>Techniques for handling platform-specific dependencies (OpenSSL, libgit2, system libraries) during cross-compilation</li><li>How to set up CI matrix builds that produce binaries for all supported platforms in parallel using GitHub Actions</li></ul></blockquote><p>Your coding agent needs to run on your user&#39;s machine, and your users are not all on the same OS or architecture. Some are on macOS with Apple Silicon, others on Intel Macs, many on Linux x86_64 servers, and a growing number on Windows. Cross-compilation is the process of building binaries for a platform different from the one you are developing on. Rust has first-class support for this, and with the right tooling, you can produce binaries for every major platform from a single machine or CI runner.</p><h2 id="understanding-targets" tabindex="-1">Understanding Targets <a class="header-anchor" href="#understanding-targets" aria-label="Permalink to &quot;Understanding Targets&quot;">​</a></h2><p>Rust uses &quot;target triples&quot; to identify platforms. A target triple encodes three pieces of information: architecture, vendor/OS, and ABI (application binary interface):</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>x86_64-unknown-linux-gnu</span></span>
<span class="line"><span>  ^         ^       ^</span></span>
<span class="line"><span>  |         |       |</span></span>
<span class="line"><span>  arch      OS    ABI/libc</span></span></code></pre></div><p>Here are the targets that matter for a coding agent:</p><table tabindex="0"><thead><tr><th>Target Triple</th><th>Platform</th><th>Notes</th></tr></thead><tbody><tr><td><code>x86_64-apple-darwin</code></td><td>macOS Intel</td><td>Older Macs (pre-2020)</td></tr><tr><td><code>aarch64-apple-darwin</code></td><td>macOS Apple Silicon</td><td>M1/M2/M3/M4 Macs</td></tr><tr><td><code>x86_64-unknown-linux-gnu</code></td><td>Linux x86_64 (glibc)</td><td>Most desktop/server Linux</td></tr><tr><td><code>x86_64-unknown-linux-musl</code></td><td>Linux x86_64 (musl)</td><td>Fully static binary</td></tr><tr><td><code>aarch64-unknown-linux-gnu</code></td><td>Linux ARM64 (glibc)</td><td>AWS Graviton, Raspberry Pi</td></tr><tr><td><code>aarch64-unknown-linux-musl</code></td><td>Linux ARM64 (musl)</td><td>Static ARM64 binary</td></tr><tr><td><code>x86_64-pc-windows-msvc</code></td><td>Windows x86_64</td><td>Standard Windows build</td></tr></tbody></table><p>You can see all installed targets and add new ones with <code>rustup</code>:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;"># List installed targets</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">rustup</span><span style="color:#A6E3A1;"> target</span><span style="color:#A6E3A1;"> list</span><span style="color:#A6E3A1;"> --installed</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Add a new target</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">rustup</span><span style="color:#A6E3A1;"> target</span><span style="color:#A6E3A1;"> add</span><span style="color:#A6E3A1;"> x86_64-unknown-linux-musl</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">rustup</span><span style="color:#A6E3A1;"> target</span><span style="color:#A6E3A1;"> add</span><span style="color:#A6E3A1;"> aarch64-apple-darwin</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Build for a specific target</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">cargo</span><span style="color:#A6E3A1;"> build</span><span style="color:#A6E3A1;"> --release</span><span style="color:#A6E3A1;"> --target</span><span style="color:#A6E3A1;"> x86_64-unknown-linux-musl</span></span></code></pre></div><div class="custom-block python"><p class="custom-block-title">Coming from Python</p><p>Python&#39;s cross-platform story is completely different. You do not cross-compile Python code -- it is interpreted. But when your Python package has C extensions (numpy, cryptography, etc.), distributing across platforms becomes a nightmare. The <code>manylinux</code> project exists specifically to solve the &quot;it compiled on my machine&quot; problem for Linux wheels. The <code>cibuildwheel</code> tool orchestrates building wheels across platforms in CI. Rust sidesteps all of this: you cross-compile to a target triple and get a native binary. No wheels, no manylinux, no compatibility tags.</p></div><h2 id="simple-cross-compilation-with-rustup" tabindex="-1">Simple Cross-Compilation with rustup <a class="header-anchor" href="#simple-cross-compilation-with-rustup" aria-label="Permalink to &quot;Simple Cross-Compilation with rustup&quot;">​</a></h2><p>For pure Rust code with no C dependencies, cross-compilation is straightforward. Add the target and build:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;"># On an Apple Silicon Mac, build for Intel Mac</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">rustup</span><span style="color:#A6E3A1;"> target</span><span style="color:#A6E3A1;"> add</span><span style="color:#A6E3A1;"> x86_64-apple-darwin</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">cargo</span><span style="color:#A6E3A1;"> build</span><span style="color:#A6E3A1;"> --release</span><span style="color:#A6E3A1;"> --target</span><span style="color:#A6E3A1;"> x86_64-apple-darwin</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># The binary lands in target/x86_64-apple-darwin/release/</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">ls</span><span style="color:#A6E3A1;"> target/x86_64-apple-darwin/release/my-agent</span></span></code></pre></div><p>This works seamlessly within the same OS (macOS-to-macOS, Linux-to-Linux) because the system linker can handle both architectures. Cross-OS compilation (macOS-to-Linux) requires a cross-linker, which is where the tooling gets more involved.</p><h2 id="the-cross-tool" tabindex="-1">The <code>cross</code> Tool <a class="header-anchor" href="#the-cross-tool" aria-label="Permalink to &quot;The \`cross\` Tool&quot;">​</a></h2><p>The <a href="https://github.com/cross-rs/cross" target="_blank" rel="noreferrer"><code>cross</code></a> project provides Docker-based cross-compilation that &quot;just works&quot; for most targets. It wraps Cargo and transparently runs your build inside a Docker container that has the right cross-compilation toolchain:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;"># Install cross</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">cargo</span><span style="color:#A6E3A1;"> install</span><span style="color:#A6E3A1;"> cross</span><span style="color:#A6E3A1;"> --git</span><span style="color:#A6E3A1;"> https://github.com/cross-rs/cross</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Build for Linux from macOS -- no manual toolchain setup</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">cross</span><span style="color:#A6E3A1;"> build</span><span style="color:#A6E3A1;"> --release</span><span style="color:#A6E3A1;"> --target</span><span style="color:#A6E3A1;"> x86_64-unknown-linux-gnu</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">cross</span><span style="color:#A6E3A1;"> build</span><span style="color:#A6E3A1;"> --release</span><span style="color:#A6E3A1;"> --target</span><span style="color:#A6E3A1;"> x86_64-unknown-linux-musl</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">cross</span><span style="color:#A6E3A1;"> build</span><span style="color:#A6E3A1;"> --release</span><span style="color:#A6E3A1;"> --target</span><span style="color:#A6E3A1;"> aarch64-unknown-linux-gnu</span></span></code></pre></div><p><code>cross</code> handles the hard parts: it provides the right GCC/musl cross-compiler, sets up sysroots with the right headers, and configures the linker. You use it exactly like <code>cargo</code> -- same flags, same behavior, just a different command name.</p><p>The main requirement is Docker (or Podman). If your CI runners have Docker available, <code>cross</code> works beautifully. If Docker is not an option, you need <code>cargo-zigbuild</code>.</p><h2 id="cargo-zigbuild-cross-compile-without-docker" tabindex="-1"><code>cargo-zigbuild</code>: Cross-Compile Without Docker <a class="header-anchor" href="#cargo-zigbuild-cross-compile-without-docker" aria-label="Permalink to &quot;\`cargo-zigbuild\`: Cross-Compile Without Docker&quot;">​</a></h2><p><a href="https://github.com/rust-cross/cargo-zigbuild" target="_blank" rel="noreferrer"><code>cargo-zigbuild</code></a> uses the Zig compiler&#39;s cross-compilation toolchain as a drop-in C/C++ cross-compiler. Zig bundles sysroots for many platforms, so you do not need Docker containers or manual toolchain installation:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;"># Install cargo-zigbuild</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">cargo</span><span style="color:#A6E3A1;"> install</span><span style="color:#A6E3A1;"> cargo-zigbuild</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Install Zig (macOS)</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">brew</span><span style="color:#A6E3A1;"> install</span><span style="color:#A6E3A1;"> zig</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Cross-compile for Linux from macOS</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">cargo</span><span style="color:#A6E3A1;"> zigbuild</span><span style="color:#A6E3A1;"> --release</span><span style="color:#A6E3A1;"> --target</span><span style="color:#A6E3A1;"> x86_64-unknown-linux-gnu</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">cargo</span><span style="color:#A6E3A1;"> zigbuild</span><span style="color:#A6E3A1;"> --release</span><span style="color:#A6E3A1;"> --target</span><span style="color:#A6E3A1;"> x86_64-unknown-linux-musl</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">cargo</span><span style="color:#A6E3A1;"> zigbuild</span><span style="color:#A6E3A1;"> --release</span><span style="color:#A6E3A1;"> --target</span><span style="color:#A6E3A1;"> aarch64-unknown-linux-gnu</span></span></code></pre></div><p>A major advantage of <code>cargo-zigbuild</code> is glibc version targeting. You can specify the minimum glibc version your binary requires:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;"># Target glibc 2.17 (CentOS 7 / Amazon Linux 2 compatibility)</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">cargo</span><span style="color:#A6E3A1;"> zigbuild</span><span style="color:#A6E3A1;"> --release</span><span style="color:#A6E3A1;"> --target</span><span style="color:#A6E3A1;"> x86_64-unknown-linux-gnu.2.17</span></span></code></pre></div><p>This ensures your binary runs on older Linux distributions without the &quot;GLIBC_2.28 not found&quot; errors that plague many Rust binaries built on modern systems.</p><h2 id="handling-c-dependencies" tabindex="-1">Handling C Dependencies <a class="header-anchor" href="#handling-c-dependencies" aria-label="Permalink to &quot;Handling C Dependencies&quot;">​</a></h2><p>The challenge with cross-compilation is C dependencies. If your coding agent uses crates that link to system C libraries, you need those libraries compiled for the target platform. Common offenders:</p><table tabindex="0"><thead><tr><th>Crate</th><th>C Dependency</th><th>Cross-Compile Solution</th></tr></thead><tbody><tr><td><code>openssl</code></td><td>libssl, libcrypto</td><td>Use <code>rustls</code> instead (pure Rust)</td></tr><tr><td><code>git2</code></td><td>libgit2, libssh2</td><td>Enable <code>vendored</code> feature</td></tr><tr><td><code>reqwest</code></td><td>(depends on TLS backend)</td><td>Use <code>rustls-tls</code> feature</td></tr><tr><td><code>sqlite</code></td><td>libsqlite3</td><td>Use <code>bundled</code> feature</td></tr></tbody></table><p>The best strategy is to eliminate C dependencies wherever possible. For our coding agent:</p><div class="language-toml"><button title="Copy Code" class="copy"></button><span class="lang">toml</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#9399B2;">[</span><span style="color:#CDD6F4;">dependencies</span><span style="color:#9399B2;">]</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Use rustls instead of OpenSSL for TLS</span></span>
<span class="line"><span style="color:#CDD6F4;">reqwest </span><span style="color:#94E2D5;">=</span><span style="color:#9399B2;"> {</span><span style="color:#CDD6F4;"> version </span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;"> &quot;0.12&quot;</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> default-features </span><span style="color:#94E2D5;">=</span><span style="color:#FAB387;"> false</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> features </span><span style="color:#94E2D5;">=</span><span style="color:#9399B2;"> [</span></span>
<span class="line"><span style="color:#A6E3A1;">    &quot;rustls-tls&quot;</span><span style="color:#9399B2;">,</span><span style="color:#A6E3A1;"> &quot;json&quot;</span><span style="color:#9399B2;">,</span><span style="color:#A6E3A1;"> &quot;stream&quot;</span></span>
<span class="line"><span style="color:#9399B2;">]</span><span style="color:#9399B2;"> }</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Vendor libgit2 so it compiles from source during the build</span></span>
<span class="line"><span style="color:#CDD6F4;">git2 </span><span style="color:#94E2D5;">=</span><span style="color:#9399B2;"> {</span><span style="color:#CDD6F4;"> version </span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;"> &quot;0.19&quot;</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> features </span><span style="color:#94E2D5;">=</span><span style="color:#9399B2;"> [</span><span style="color:#A6E3A1;">&quot;vendored&quot;</span><span style="color:#9399B2;">]</span><span style="color:#9399B2;"> }</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Bundled SQLite compiles from C source -- no system library needed</span></span>
<span class="line"><span style="color:#CDD6F4;">rusqlite </span><span style="color:#94E2D5;">=</span><span style="color:#9399B2;"> {</span><span style="color:#CDD6F4;"> version </span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;"> &quot;0.32&quot;</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> features </span><span style="color:#94E2D5;">=</span><span style="color:#9399B2;"> [</span><span style="color:#A6E3A1;">&quot;bundled&quot;</span><span style="color:#9399B2;">]</span><span style="color:#9399B2;"> }</span></span></code></pre></div><p>The <code>vendored</code> and <code>bundled</code> features tell these crates to compile their C dependencies from source rather than linking to the system library. This makes cross-compilation work because the C code is compiled with the cross-compiler alongside your Rust code.</p><details class="details custom-block"><summary>Why not always vendor everything?</summary><p>Vendoring increases build times (you are compiling C code from source) and can introduce version mismatches if the bundled version has known vulnerabilities that the system version has patched. For distribution builds, vendoring is the right call. For development, linking to system libraries is fine.</p></details><h2 id="configuring-linkers-per-target" tabindex="-1">Configuring Linkers Per Target <a class="header-anchor" href="#configuring-linkers-per-target" aria-label="Permalink to &quot;Configuring Linkers Per Target&quot;">​</a></h2><p>When you cross-compile without <code>cross</code> or <code>cargo-zigbuild</code>, you need to tell Cargo which linker to use for each target. This is configured in <code>.cargo/config.toml</code>:</p><div class="language-toml"><button title="Copy Code" class="copy"></button><span class="lang">toml</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#9399B2;">[</span><span style="color:#CDD6F4;">target.x86_64-unknown-linux-gnu</span><span style="color:#9399B2;">]</span></span>
<span class="line"><span style="color:#CDD6F4;">linker </span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;"> &quot;x86_64-linux-gnu-gcc&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#9399B2;">[</span><span style="color:#CDD6F4;">target.aarch64-unknown-linux-gnu</span><span style="color:#9399B2;">]</span></span>
<span class="line"><span style="color:#CDD6F4;">linker </span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;"> &quot;aarch64-linux-gnu-gcc&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#9399B2;">[</span><span style="color:#CDD6F4;">target.x86_64-unknown-linux-musl</span><span style="color:#9399B2;">]</span></span>
<span class="line"><span style="color:#CDD6F4;">linker </span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;"> &quot;x86_64-linux-musl-gcc&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#9399B2;">[</span><span style="color:#CDD6F4;">target.x86_64-pc-windows-msvc</span><span style="color:#9399B2;">]</span></span>
<span class="line"><span style="color:#CDD6F4;">linker </span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;"> &quot;lld-link&quot;</span></span></code></pre></div><p>On Ubuntu, install the cross-compilers:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#89B4FA;font-style:italic;">sudo</span><span style="color:#A6E3A1;"> apt</span><span style="color:#A6E3A1;"> install</span><span style="color:#A6E3A1;"> gcc-x86-64-linux-gnu</span><span style="color:#A6E3A1;"> gcc-aarch64-linux-gnu</span><span style="color:#A6E3A1;"> musl-tools</span></span></code></pre></div><p>On macOS, the Xcode toolchain handles both <code>x86_64-apple-darwin</code> and <code>aarch64-apple-darwin</code> natively. For Linux targets from macOS, use <code>cross</code> or <code>cargo-zigbuild</code> rather than manually installing cross-linkers.</p><h2 id="ci-matrix-builds-with-github-actions" tabindex="-1">CI Matrix Builds with GitHub Actions <a class="header-anchor" href="#ci-matrix-builds-with-github-actions" aria-label="Permalink to &quot;CI Matrix Builds with GitHub Actions&quot;">​</a></h2><p>The practical approach for production is to build each platform on its native runner in CI. Here is a GitHub Actions workflow that builds for all major targets:</p><div class="language-yaml"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#89B4FA;">name</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> Release</span></span>
<span class="line"></span>
<span class="line"><span style="color:#FAB387;">on</span><span style="color:#94E2D5;">:</span></span>
<span class="line"><span style="color:#89B4FA;">  push</span><span style="color:#94E2D5;">:</span></span>
<span class="line"><span style="color:#89B4FA;">    tags</span><span style="color:#94E2D5;">:</span><span style="color:#9399B2;"> [</span><span style="color:#A6E3A1;">&quot;v*&quot;</span><span style="color:#9399B2;">]</span></span>
<span class="line"></span>
<span class="line"><span style="color:#89B4FA;">jobs</span><span style="color:#94E2D5;">:</span></span>
<span class="line"><span style="color:#89B4FA;">  build</span><span style="color:#94E2D5;">:</span></span>
<span class="line"><span style="color:#89B4FA;">    strategy</span><span style="color:#94E2D5;">:</span></span>
<span class="line"><span style="color:#89B4FA;">      matrix</span><span style="color:#94E2D5;">:</span></span>
<span class="line"><span style="color:#89B4FA;">        include</span><span style="color:#94E2D5;">:</span></span>
<span class="line"><span style="color:#9399B2;">          -</span><span style="color:#89B4FA;"> target</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> x86_64-apple-darwin</span></span>
<span class="line"><span style="color:#89B4FA;">            os</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> macos-latest</span></span>
<span class="line"><span style="color:#9399B2;">          -</span><span style="color:#89B4FA;"> target</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> aarch64-apple-darwin</span></span>
<span class="line"><span style="color:#89B4FA;">            os</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> macos-latest</span></span>
<span class="line"><span style="color:#9399B2;">          -</span><span style="color:#89B4FA;"> target</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> x86_64-unknown-linux-gnu</span></span>
<span class="line"><span style="color:#89B4FA;">            os</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> ubuntu-latest</span></span>
<span class="line"><span style="color:#9399B2;">          -</span><span style="color:#89B4FA;"> target</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> x86_64-unknown-linux-musl</span></span>
<span class="line"><span style="color:#89B4FA;">            os</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> ubuntu-latest</span></span>
<span class="line"><span style="color:#9399B2;">          -</span><span style="color:#89B4FA;"> target</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> aarch64-unknown-linux-gnu</span></span>
<span class="line"><span style="color:#89B4FA;">            os</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> ubuntu-latest</span></span>
<span class="line"><span style="color:#89B4FA;">            use_cross</span><span style="color:#94E2D5;">:</span><span style="color:#FAB387;"> true</span></span>
<span class="line"><span style="color:#9399B2;">          -</span><span style="color:#89B4FA;"> target</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> x86_64-pc-windows-msvc</span></span>
<span class="line"><span style="color:#89B4FA;">            os</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> windows-latest</span></span>
<span class="line"></span>
<span class="line"><span style="color:#89B4FA;">    runs-on</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> \${{ matrix.os }}</span></span>
<span class="line"></span>
<span class="line"><span style="color:#89B4FA;">    steps</span><span style="color:#94E2D5;">:</span></span>
<span class="line"><span style="color:#9399B2;">      -</span><span style="color:#89B4FA;"> uses</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> actions/checkout@v4</span></span>
<span class="line"></span>
<span class="line"><span style="color:#9399B2;">      -</span><span style="color:#89B4FA;"> uses</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> dtolnay/rust-toolchain@stable</span></span>
<span class="line"><span style="color:#89B4FA;">        with</span><span style="color:#94E2D5;">:</span></span>
<span class="line"><span style="color:#89B4FA;">          targets</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> \${{ matrix.target }}</span></span>
<span class="line"></span>
<span class="line"><span style="color:#9399B2;">      -</span><span style="color:#89B4FA;"> name</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> Install cross</span></span>
<span class="line"><span style="color:#89B4FA;">        if</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> matrix.use_cross</span></span>
<span class="line"><span style="color:#89B4FA;">        run</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> cargo install cross --git https://github.com/cross-rs/cross</span></span>
<span class="line"></span>
<span class="line"><span style="color:#9399B2;">      -</span><span style="color:#89B4FA;"> name</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> Install musl-tools</span></span>
<span class="line"><span style="color:#89B4FA;">        if</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> contains(matrix.target, &#39;musl&#39;)</span></span>
<span class="line"><span style="color:#89B4FA;">        run</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> sudo apt install -y musl-tools</span></span>
<span class="line"></span>
<span class="line"><span style="color:#9399B2;">      -</span><span style="color:#89B4FA;"> name</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> Build</span></span>
<span class="line"><span style="color:#89B4FA;">        run</span><span style="color:#94E2D5;">:</span><span style="color:#CBA6F7;"> |</span></span>
<span class="line"><span style="color:#A6E3A1;">          if [ &quot;\${{ matrix.use_cross }}&quot; = &quot;true&quot; ]; then</span></span>
<span class="line"><span style="color:#A6E3A1;">            cross build --release --target \${{ matrix.target }}</span></span>
<span class="line"><span style="color:#A6E3A1;">          else</span></span>
<span class="line"><span style="color:#A6E3A1;">            cargo build --release --target \${{ matrix.target }}</span></span>
<span class="line"><span style="color:#A6E3A1;">          fi</span></span>
<span class="line"><span style="color:#89B4FA;">        shell</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> bash</span></span>
<span class="line"></span>
<span class="line"><span style="color:#9399B2;">      -</span><span style="color:#89B4FA;"> name</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> Upload artifact</span></span>
<span class="line"><span style="color:#89B4FA;">        uses</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> actions/upload-artifact@v4</span></span>
<span class="line"><span style="color:#89B4FA;">        with</span><span style="color:#94E2D5;">:</span></span>
<span class="line"><span style="color:#89B4FA;">          name</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> binary-\${{ matrix.target }}</span></span>
<span class="line"><span style="color:#89B4FA;">          path</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> target/\${{ matrix.target }}/release/my-agent*</span></span></code></pre></div><p>This workflow uses native runners for platforms that support direct compilation (macOS builds macOS targets, Ubuntu builds Linux x86_64 targets) and <code>cross</code> for targets that need a cross-compiler (ARM64 Linux from x86_64 Ubuntu).</p><div class="custom-block wild"><p class="custom-block-title">In the Wild</p><p>Production coding agents like Claude Code build for multiple platforms in CI pipelines. The typical approach is a matrix build that produces binaries for macOS (both architectures), Linux (both glibc and musl), and sometimes Windows. The musl builds are particularly important because they produce fully static binaries that run on any Linux distribution without glibc version conflicts.</p></div><h2 id="universal-binaries-on-macos" tabindex="-1">Universal Binaries on macOS <a class="header-anchor" href="#universal-binaries-on-macos" aria-label="Permalink to &quot;Universal Binaries on macOS&quot;">​</a></h2><p>macOS supports &quot;universal binaries&quot; (also called &quot;fat binaries&quot;) that contain code for both Intel and Apple Silicon. You can create one with the <code>lipo</code> tool:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;"># Build for both architectures</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">cargo</span><span style="color:#A6E3A1;"> build</span><span style="color:#A6E3A1;"> --release</span><span style="color:#A6E3A1;"> --target</span><span style="color:#A6E3A1;"> x86_64-apple-darwin</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">cargo</span><span style="color:#A6E3A1;"> build</span><span style="color:#A6E3A1;"> --release</span><span style="color:#A6E3A1;"> --target</span><span style="color:#A6E3A1;"> aarch64-apple-darwin</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Combine into a universal binary</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">lipo</span><span style="color:#A6E3A1;"> -create</span><span style="color:#F5C2E7;"> \\</span></span>
<span class="line"><span style="color:#A6E3A1;">  target/x86_64-apple-darwin/release/my-agent</span><span style="color:#F5C2E7;"> \\</span></span>
<span class="line"><span style="color:#A6E3A1;">  target/aarch64-apple-darwin/release/my-agent</span><span style="color:#F5C2E7;"> \\</span></span>
<span class="line"><span style="color:#A6E3A1;">  -output</span><span style="color:#A6E3A1;"> target/my-agent-universal</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Verify</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">file</span><span style="color:#A6E3A1;"> target/my-agent-universal</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># target/my-agent-universal: Mach-O universal binary with 2 architectures:</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">#   Mach-O 64-bit executable x86_64</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">#   Mach-O 64-bit executable arm64</span></span></code></pre></div><p>Universal binaries are larger (roughly double the size of a single-architecture binary) but simplify distribution: you ship one file that works on all Macs. Homebrew formulas often use universal binaries to avoid architecture detection logic.</p><h2 id="key-takeaways" tabindex="-1">Key Takeaways <a class="header-anchor" href="#key-takeaways" aria-label="Permalink to &quot;Key Takeaways&quot;">​</a></h2><ul><li>Rust identifies platforms with target triples (e.g., <code>x86_64-unknown-linux-musl</code>) and you can add targets with <code>rustup target add</code>.</li><li>Use <code>cross</code> (Docker-based) or <code>cargo-zigbuild</code> (Zig-based) to cross-compile for Linux from macOS without manual toolchain setup.</li><li>Eliminate C dependencies where possible -- use <code>rustls</code> instead of OpenSSL, enable <code>vendored</code>/<code>bundled</code> features for unavoidable C libraries.</li><li>CI matrix builds on native runners are the most reliable approach: let macOS runners build macOS binaries, Linux runners build Linux binaries.</li><li>Use <code>lipo</code> to create macOS universal binaries that work on both Intel and Apple Silicon.</li></ul>`,50)])])}const A=a(e,[["render",t]]);export{y as __pageData,A as default};
